#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, P;
        scanf("%d %d %d", &N, &M, &P);
        int **graph = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            graph[i] = (int *)malloc(N * sizeof(int));
            for (int j = 0; j < N; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < M; i++) {
            int Xi, Yi;
            scanf("%d %d", &Xi, &Yi);
            graph[Xi - 1][Yi - 1] = 1;
            graph[Yi - 1][Xi - 1] = 1;
        }
        if (P >= N - 1 || M < N - 1) {
            printf("First\n");
        } else {
            printf("Second\n");
        }
        for (int i = 0; i < N; i++) {
            free(graph[i]);
        }
        free(graph);
    }
    return 0;
}

